// accordion
if (document.querySelector('.body__accordion')) {
   function openTab(evt, tabName) {
      let i, tabcontent, tablinks;
      tabcontent = document.getElementsByClassName('accordion__item');
      for (i = 0; i < tabcontent.length; i++) {
         tabcontent[i].style.display = 'none';
      }
      tablinks = document.getElementsByClassName('accordion__header');
      for (i = 0; i < tablinks.length; i++) {
         tablinks[i].className = tablinks[i].className.replace(' show', '');
      }
      document.getElementById(tabName).style.display = 'flex';
      evt.currentTarget.className += ' show';
   }
}
